import{_ as a,o as r,c as e,ae as l}from"./chunks/framework.DAK3ioSj.js";const c=JSON.parse('{"title":"Skill 管理（Management）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-06-management.md","filePath":"radar/category-06-management.md"}'),o={name:"radar/category-06-management.md"};function n(d,t,s,i,h,g){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="skill-管理-management" tabindex="-1">Skill 管理（Management） <a class="header-anchor" href="#skill-管理-management" aria-label="Permalink to &quot;Skill 管理（Management）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟡 成长期（边界） · <strong>综合评分</strong>: <strong>0.40</strong></p><p><strong>业界判断</strong>：<strong>Vercel skills.sh（90K+ Skill / 19 个 Agent 框架）</strong> 给了事实分发标准、agentskills.io 形成开放规范，但 <strong>攻防仍最不对称</strong> —— 26.1% 社区 Skill 含漏洞、OWASP Top 10 已立项、自动化扫描工具仍为零。版本管理、灰度发布、模型升级兼容性也全部空白。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>核心路径</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-skills-sh.html">Vercel skills.sh</a></td><td>Vercel (2026-01)</td><td>工业级分发 + 排行榜</td><td><strong>90,000+ Skill / 19 Agent 框架</strong></td></tr><tr><td><a href="./tech-skillnet.html">SkillNet</a></td><td>浙大 NLP (735 ★)</td><td>200K+ Skill 集中式公共市场</td><td>5 维评分体系</td></tr><tr><td><a href="./tech-agentskillos.html">AgentSkillOS</a></td><td>学术</td><td>Capability Tree 生命周期管理</td><td>200–200K 规模逼近理想</td></tr><tr><td><a href="./tech-skills-standard.html">Agent Skills 标准</a></td><td>社区开放标准（Anthropic 发起）</td><td>跨平台格式与协议</td><td>~38+ 产品采用</td></tr></tbody></table><hr><h2 id="行业安全现状" tabindex="-1">行业安全现状 <a class="header-anchor" href="#行业安全现状" aria-label="Permalink to &quot;行业安全现状&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>数据</th></tr></thead><tbody><tr><td>社区 Skill 含安全漏洞比例</td><td><strong>26.1%</strong> （42,447 个 Skill 分析）</td></tr><tr><td>安全问题需要跨模态检测的比例</td><td><strong>76.3%</strong> （同时看 NL 描述和代码）</td></tr><tr><td>OWASP 状态</td><td>已发布 <a href="https://owasp.org/www-project-agentic-skills-top-10/" target="_blank" rel="noreferrer">Agentic Skills Top 10</a></td></tr><tr><td>已确认 CVE</td><td>多个</td></tr></tbody></table><p><strong>目前只有两种极端：</strong></p><ul><li><strong>全封闭</strong> —— Hermes 仅 118 个审核过的内置 Skill</li><li><strong>全裸奔</strong> —— OpenClaw 13K+ 社区 Skill + 9 个 CVE</li></ul><p><strong>缺少中间路径</strong>。</p><hr><h2 id="行业核心痛点" tabindex="-1">行业核心痛点 <a class="header-anchor" href="#行业核心痛点" aria-label="Permalink to &quot;行业核心痛点&quot;">​</a></h2><h3 id="🔴-安全防御工具完全为零" tabindex="-1">🔴 安全防御工具完全为零 <a class="header-anchor" href="#🔴-安全防御工具完全为零" aria-label="Permalink to &quot;🔴 安全防御工具完全为零&quot;">​</a></h3><p>26.1% 漏洞率 + 0 个自动化扫描工具 = 最不对称的攻防格局。OWASP 发布了指南级框架，但<strong>没有任何自动化扫描工具让使用者在安装前检查 Skill 是否安全</strong>。</p><h3 id="🔴-进化-安全的交叉空白" tabindex="-1">🔴 进化 + 安全的交叉空白 <a class="header-anchor" href="#🔴-进化-安全的交叉空白" aria-label="Permalink to &quot;🔴 进化 + 安全的交叉空白&quot;">​</a></h3><p>8 个进化框架都在自动生成 Skill，<strong>没有一个在进化循环中加入安全扫描</strong> —— 进化可能无意中引入漏洞。</p><h3 id="⚪-模型升级兼容性的定时炸弹" tabindex="-1">⚪ 模型升级兼容性的定时炸弹 <a class="header-anchor" href="#⚪-模型升级兼容性的定时炸弹" aria-label="Permalink to &quot;⚪ 模型升级兼容性的定时炸弹&quot;">​</a></h3><p>升级了 Claude 版本，原来好用的 Skill 突然不灵了，<strong>不知道哪些受影响</strong>。主流 LLM 每 2-3 个月发布新版本 × 数十万 Skill = 指数增长的兼容性风险。<strong>完全空白</strong>。</p><h3 id="⚪-废弃-skill-识别" tabindex="-1">⚪ 废弃 Skill 识别 <a class="header-anchor" href="#⚪-废弃-skill-识别" aria-label="Permalink to &quot;⚪ 废弃 Skill 识别&quot;">​</a></h3><p>Skill 库越来越臃肿，一半都过时了，但删了怕影响其他东西 —— 像不敢清的 node_modules。SkillNet 的关系图谱能理解依赖，但<strong>没有&quot;安全删除向导&quot;</strong>。</p><h3 id="❌-版本管理与灰度发布" tabindex="-1">❌ 版本管理与灰度发布 <a class="header-anchor" href="#❌-版本管理与灰度发布" aria-label="Permalink to &quot;❌ 版本管理与灰度发布&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>状态</th></tr></thead><tbody><tr><td>团队成员统一管理 Skill</td><td>skills.sh / SkillNet 解决公开发现分发，<strong>不解决团队内部治理</strong></td></tr><tr><td>版本一致性</td><td><strong>完全空白</strong>。Hermes 的 <code>version: 1.0.0</code> 字段只是 schema 占位</td></tr><tr><td>各自优化后归并</td><td><strong>完全空白</strong>。两人对同一段自然语言指令的不同修改如何判断冲突？</td></tr><tr><td>灰度发布 / 自动回滚</td><td><strong>完全空白</strong>。Hermes PR 模式是最接近的，但需要人工审核</td></tr></tbody></table><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><blockquote><p>管理阶段是整个 Skill 生态中<strong>最不成熟</strong>、<strong>最不对称</strong>、<strong>最有机会的</strong>的赛道 —— 攻击面已被充分研究，防御工具几乎为零。</p></blockquote>',26)])])}const m=a(o,[["render",n]]);export{c as __pageData,m as default};
